  const handleReadAloud = () => {
    if (!activeEntry) return;
    if (isSpeaking && speakingId === 'atlas-summary') {
        cancel();
    } else {
        const points = activeEntry.related.map((p, i) => {
            const label = p.questionText.replace(/^In the diagram,?\s*/i, '').replace(/^Identify the\s+/i, '').replace(/\??$/i, '');
            return `Point ${i + 1}: ${label}. ${p.answerText}`;
        }).join('. ');

        const fullText = `Structure Breakdown for ${activeEntry.title}. ${points}`;
        speak(fullText, 'atlas-summary');
    }
  };

  const filterOptions: FilterOption[] = [
    {
        label: 'Mistakes Gallery',
        subLabel: `${mistakesVault.length} Active Errors`,
        icon: AlertTriangle,
        isActive: showMistakesOnly,
        onClick: () => { setShowMistakesOnly(!showMistakesOnly); if(!showMistakesOnly) { setSelectedCategories([]); } },
        colorTheme: 'amber'
    }
  ];

  return (
    <div className="h-full flex flex-col bg-slate-50/50 relative">

      {/* Sticky Header Control Bar */}
      <div className="px-4 py-4 md:px-8 md:py-6 sticky top-0 z-40 bg-white/80 backdrop-blur-md border-b border-slate-200/60 shadow-sm">
        <div className="max-w-7xl mx-auto flex gap-3 md:gap-4 items-center">
            <div className="flex-1 relative group">
                <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none">
                    <Search className="text-slate-400 group-focus-within:text-rose-500 transition-colors" size={18} />
                </div>
                <input 
                    type="text" 
                    placeholder={showMistakesOnly ? "Search errors in diagrams..." : "Search anatomical structures..."} 
                    value={search}
                    onChange={(e) => setSearch(e.target.value)}
                    className="w-full pl-11 pr-4 py-3 rounded-xl bg-slate-100/50 border border-slate-200 text-slate-700 font-medium text-sm focus:bg-white focus:border-rose-300 focus:ring-4 focus:ring-rose-100 outline-none transition-all placeholder:text-slate-400"
                />
            </div>
            <button 
                onClick={() => setIsFilterOpen(true)}
                className={`h-[46px] px-4 md:px-6 rounded-xl border transition-all flex items-center gap-2 font-bold text-xs uppercase tracking-wider ${
                    selectedCategories.length > 0 || showMistakesOnly 
                    ? 'bg-rose-50 border-rose-200 text-rose-700' 
                    : 'bg-white border-slate-200 text-slate-600 hover:border-slate-300'
                }`}
            >
                <Filter size={16} />
                <span className="hidden md:inline">Filters</span>
                {(selectedCategories.length > 0 || showMistakesOnly) && (
                    <span className="flex h-5 w-5 items-center justify-center rounded-full bg-rose-600 text-[9px] text-white ml-1">
                        {[selectedCategories.length > 0, showMistakesOnly].filter(Boolean).length}
                    </span>
                )}
            </button>
        </div>

        {/* Diagnostic Mode Banner */}
        {showMistakesOnly && (
            <div className="max-w-7xl mx-auto mt-3 animate-in slide-in-from-top-2 fade-in">
                <div className="bg-amber-50 border border-amber-100 rounded-lg px-4 py-2 flex items-center justify-between text-amber-800 shadow-sm">
                    <div className="flex items-center gap-2">
                        <AlertTriangle size={16} className="text-amber-600" />
                        <span className="text-xs font-bold uppercase tracking-wide">Diagnostic Mode Active</span>
                    </div>
                    <span className="text-[10px] font-bold opacity-70">{atlasItems.length} Diagrams Found</span>
                </div>
            </div>
        )}
      </div>

      {/* Main Content Grid */}
      <div className="flex-1 overflow-y-auto px-4 md:px-8 py-6 custom-scrollbar scroll-smooth">
        <div className="max-w-7xl mx-auto pb-32">
            {atlasItems.length > 0 ? (
                <>
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6 content-visibility-auto">
                    {visibleItems.map((item, idx) => (
                        <div 
                            key={idx} 
                            onClick={() => setSelectedImage(item.url)}
                            className="group cursor-pointer bg-white rounded-2xl border border-slate-100 shadow-card hover:shadow-card-hover hover:-translate-y-1 transition-all duration-300 flex flex-col overflow-hidden relative"
                        >
                            <div className="aspect-[4/3] bg-slate-50 relative overflow-hidden flex items-center justify-center p-4 border-b border-slate-50">
                                <img 
                                    src={cleanImageUrl(item.url)} 
                                    className="max-w-full max-h-full object-contain transition-transform duration-700 group-hover:scale-105" 
                                    alt="Anatomy Diagram" 
                                    loading="lazy" 
                                />
                                <div className="absolute inset-0 bg-slate-900/0 group-hover:bg-slate-900/5 transition-colors z-10 flex items-center justify-center">
                                    <div className="bg-white/90 backdrop-blur-sm text-slate-900 px-3 py-2 rounded-full font-bold text-[10px] uppercase tracking-widest shadow-lg opacity-0 translate-y-2 group-hover:opacity-100 group-hover:translate-y-0 transition-all duration-300 flex items-center gap-2 transform">
                                        <PlayCircle size={14} className="text-rose-500" /> Start Quiz
                                    </div>
                                </div>
                                {item.hasMistake && (
                                    <div className="absolute top-2 right-2 z-20 bg-amber-100 text-amber-600 p-1.5 rounded-lg shadow-sm">
                                        <AlertTriangle size={14} />
                                    </div>
                                )}
                            </div>
                            <div className="p-4 flex-1 flex flex-col justify-between">
                                <div className="space-y-2">
                                    <span className="inline-block px-2 py-0.5 rounded text-[9px] font-black uppercase tracking-widest text-slate-400 border border-slate-100 bg-slate-50 truncate max-w-full">
                                        {item.category.split(':')[0]}
                                    </span>
                                    <h3 className="font-display font-bold text-slate-800 text-sm leading-snug line-clamp-2 group-hover:text-rose-600 transition-colors">
                                        {item.title}
                                    </h3>
                                </div>
                                <div className="mt-4 pt-3 border-t border-slate-50 flex items-center justify-between text-slate-400">
                                    <span className="text-[10px] font-bold uppercase tracking-wider flex items-center gap-1.5">
                                        <Layers size={14} className="text-slate-300" /> {item.related.length} Features
                                    </span>
                                    <ChevronRight size={14} className="group-hover:translate-x-1 transition-transform text-rose-300" />
                                </div>
                            </div>
                        </div>
                    ))}
                </div>
                {visibleLimit < atlasItems.length && (
                    <div className="mt-12 flex justify-center">
                        <button 
                            onClick={() => setVisibleLimit(prev => prev + 24)}
                            className="px-8 py-3 bg-white border border-slate-200 text-slate-600 rounded-xl font-bold uppercase text-xs tracking-widest hover:border-slate-300 hover:bg-slate-50 hover:text-slate-900 transition-all flex items-center gap-2 shadow-sm active:scale-95"
                        >
                            Load More Diagrams <ChevronDown size={14} />
                        </button>
                    </div>
                )}
                </>
            ) : (
                <div className="flex flex-col items-center justify-center py-24 text-center space-y-4 opacity-50">
                    <MapIcon size={48} className="text-slate-300" strokeWidth={1.5} />
                    <p className="font-bold text-slate-400">No Atlas Entries Found</p>
                </div>
            )}
        </div>
      </div>

      {/* DETAILED VIEW MODAL */}
      {activeEntry && (
        <div className="fixed inset-0 z-[300] flex flex-col md:flex-row bg-slate-950/95 backdrop-blur-2xl animate-in fade-in duration-300 overflow-hidden">

          {/* Global Close Button */}
          <button 
            onClick={() => setSelectedImage(null)} 
            className="absolute top-4 right-4 z-[320] p-2.5 bg-black/40 hover:bg-black/60 text-white/90 rounded-full transition-all backdrop-blur-md border border-white/10 group shadow-lg"
          >
            <X size={22} className="group-hover:rotate-90 transition-transform" />
          </button>

          {/* Left Panel: Image */}
          <div className={`relative transition-all duration-500 ease-in-out bg-black/20 flex items-center justify-center p-4 md:p-12 overflow-hidden
            ${isImageExpanded ? 'w-full h-full absolute inset-0 z-[310]' : 'h-[38vh] w-full md:h-full md:flex-[1.6]'}
          `}>

            <img 
                src={cleanImageUrl(activeEntry.url)} 
                className={`max-w-full max-h-full object-contain rounded-lg shadow-2xl transition-all duration-500 ${isImageExpanded ? 'scale-100' : 'scale-95'}`}
                alt="Active Diagram" 
            />

            <div className="absolute bottom-4 left-1/2 -translate-x-1/2 flex items-center gap-2 z-[315]">
                <button 
                    onClick={(e) => { e.stopPropagation(); setIsImageExpanded(!isImageExpanded); }}
                    className="bg-black/60 text-white/90 px-4 py-2 rounded-full text-[10px] font-bold uppercase tracking-widest backdrop-blur-md flex items-center gap-2 border border-white/10 hover:bg-white/20 transition-all shadow-lg"
                >
                    {isImageExpanded ? <><Minimize2 size={12} /> Minimize</> : <><Maximize2 size={12} /> Expand</>}
                </button>
            </div>
          </div>

          {/* Right Panel: Content Sheet */}
          <div className={`bg-white flex flex-col shadow-2xl relative z-10 transition-all duration-500 
            ${isImageExpanded ? 'translate-y-full opacity-0 pointer-events-none absolute' : 'flex-1 h-[62vh] md:h-full md:rounded-l-[2.5rem] rounded-t-[2.5rem] md:rounded-tr-none -mt-6 md:mt-0'}
          `}>

            {/* Draggable Handle Indicator for Mobile */}
            <div className="w-12 h-1.5 bg-slate-200 rounded-full mx-auto mt-3 mb-1 md:hidden shrink-0" />

            {isQuizActive ? (
                // --- FULL EMBEDDED QUIZ MODE ---
                <div className="flex-1 flex flex-col bg-slate-50 relative overflow-hidden rounded-t-[2rem] md:rounded-none h-full">
                    <Quiz 
                        key={activeEntry.url + '-quiz'} 
                        data={activeEntry.related} 
                        isEmbedded={true} 
                        onExit={() => setIsQuizActive(false)} 
                    />
                </div>
            ) : (
                // --- STANDARD INFO LIST ---
                <div className="flex flex-col h-full overflow-hidden">
                    <div className="p-6 md:p-8 border-b border-slate-100 bg-white sticky top-0 z-10 shrink-0">
                        <div className="flex items-center gap-2 mb-3">
                            <span className="px-2 py-0.5 bg-rose-50 text-rose-600 rounded text-[9px] font-black uppercase tracking-widest border border-rose-100 truncate max-w-full">
                                {activeEntry.category.split(':')[0]}
                            </span>
                        </div>

                        <div className="flex justify-between items-start gap-4">
                            <h2 className="text-xl md:text-2xl font-display font-bold text-slate-900 leading-tight">
                                Structure Breakdown
                            </h2>
                            <div className="flex gap-2 shrink-0">
                                <button 
                                    onClick={handleReadAloud}
                                    className={`w-10 h-10 flex items-center justify-center rounded-xl border transition-all ${isSpeaking && speakingId === 'atlas-summary' ? 'bg-rose-100 border-rose-200 text-rose-600' : 'bg-white border-slate-200 text-slate-400 hover:text-slate-900 hover:border-slate-300'}`}
                                    title="Read Description"
                                >
                                    {isSpeaking && speakingId === 'atlas-summary' ? <VolumeX size={18} /> : <Volume2 size={18} />}
                                </button>
                                <button 
                                    onClick={() => setIsQuizActive(true)}
                                    className="h-10 px-5 bg-slate-900 text-white rounded-xl text-[10px] font-bold uppercase tracking-widest flex items-center gap-2 hover:bg-rose-600 transition-all shadow-lg active:scale-95 hover:shadow-rose-200"
                                >
                                    <BrainCircuit size={16} /> Practice
                                </button>
                            </div>
                        </div>
                    </div>

                    <div className="flex-1 overflow-y-auto p-4 md:p-8 custom-scrollbar space-y-4 bg-slate-50/50 pb-safe">
                        {activeEntry.related.map((point, pIdx) => {
                            const isMistake = mistakesVault.includes(point.id);
                            return (
                                <div key={pIdx} className={`relative p-5 rounded-2xl bg-white border transition-all duration-300 ${isMistake ? 'border-amber-200 ring-1 ring-amber-100 shadow-sm' : 'border-slate-100 hover:border-slate-200 hover:shadow-sm'}`}>
                                    <div className="flex justify-between items-start mb-2">
                                        <div className="flex items-center gap-3">
                                            <div className={`flex items-center justify-center w-6 h-6 rounded-full text-[10px] font-bold border ${isMistake ? 'bg-amber-50 text-amber-700 border-amber-200' : 'bg-slate-100 text-slate-500 border-slate-200'}`}>
                                                {pIdx + 1}
                                            </div>
                                            <span className="text-[10px] font-bold uppercase tracking-widest text-slate-400">Point of Interest</span>
                                        </div>

                                        {isMistake && (
                                            <button 
                                                onClick={(e) => handleResolveMistake(point.id, e)}
                                                className="flex items-center gap-1.5 px-3 py-1.5 bg-emerald-50 text-emerald-700 rounded-lg text-[10px] font-black uppercase tracking-wider hover:bg-emerald-100 transition-colors border border-emerald-100"
                                            >
                                                <CheckCircle2 size={12} /> Resolve
                                            </button>
                                        )}
                                    </div>

                                    <div className="pl-9 space-y-2">
                                        <p className="text-sm font-bold text-slate-800 leading-snug" dangerouslySetInnerHTML={{ __html: point.questionText.replace(/^In the diagram,?\s*/i, '').replace(/^Identify the\s+/i, '') }} />
                                        <div className="relative pl-3 border-l-2 border-rose-200">
                                            <p className="text-sm font-medium text-slate-600" dangerouslySetInnerHTML={{ __html: point.answerText }} />
                                        </div>
                                    </div>
                                </div>
                            );
                        })}

                        <div className="text-center py-8 opacity-50">
                            <span className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-300">End of Record</span>
                        </div>
                    </div>
                </div>
            )}
          </div>
        </div>
      )}

      <FilterModal
        isOpen={isFilterOpen}
        onClose={() => setIsFilterOpen(false)}
        categories={categories}
        selectedCategories={selectedCategories}
        onToggleCategory={(cat) => setSelectedCategories(prev => prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat])}
        onClearAll={() => { setSelectedCategories([]); setShowMistakesOnly(false); }}
        onWipeVault={mistakesVault.length > 0 ? handleWipeVault : undefined}
        mainOptions={filterOptions}
        title="Atlas Filters"
      />
    </div>
  );
};

export default InteractiveAtlas;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { Question } from '../types';
import { 
  Map as MapIcon, ChevronRight, Search, Maximize2, Minimize2, X, 
  Filter, AlertTriangle, CheckCircle2, ChevronDown, Layers, Scan,
  BrainCircuit, Volume2, VolumeX, PlayCircle
} from 'lucide-react';
import FilterModal, { FilterOption } from './FilterModal';
import { useSpeech } from '../hooks/useSpeech';
import Quiz from './Quiz';

// Robust Image Proxy
const cleanImageUrl = (url: string) => {
  if (!url) return '';
  let clean = url;
  if (url.includes('http') && url.lastIndexOf('http') > 0) {
    clean = url.substring(url.lastIndexOf('http'));
  }
  return `https://wsrv.nl/?url=${encodeURIComponent(clean)}&w=1200&q=82&output=webp&il`;
};

interface InteractiveAtlasProps {
  data: Question[];
}

const InteractiveAtlas: React.FC<InteractiveAtlasProps> = ({ data }) => {
  // --- STATE ---
  const [selectedImage, setSelectedImage] = useState<string | null>(() => {
    return localStorage.getItem('ot_atlas_selected_image') || null;
  });

  const [isImageExpanded, setIsImageExpanded] = useState(() => {
    return localStorage.getItem('ot_atlas_image_expanded') === 'true';
  });

  // Initialize quiz active state based on whether an image is selected (persistence)
  const [isQuizActive, setIsQuizActive] = useState(() => {
    return !!localStorage.getItem('ot_atlas_selected_image');
  });

  const [search, setSearch] = useState(() => {
    return localStorage.getItem('ot_atlas_search') || '';
  });

  const [visibleLimit, setVisibleLimit] = useState(24);
  const [isFilterOpen, setIsFilterOpen] = useState(false);

  const [showMistakesOnly, setShowMistakesOnly] = useState(() => {
    return localStorage.getItem('ot_atlas_filter_mistakes') === 'true';
  });

  const [selectedCategories, setSelectedCategories] = useState<string[]>(() => {
    try {
        const saved = localStorage.getItem('ot_atlas_filter_categories');
        return saved ? JSON.parse(saved) : [];
    } catch { return []; }
  });

  const isMounted = useRef(false);
  const { speak, cancel, isSpeaking, speakingId } = useSpeech();

  const [mistakesVault, setMistakesVault] = useState<string[]>(() => {
    try {
      const saved = localStorage.getItem('anatomy_mistakes_v5');
      return saved ? JSON.parse(saved) : [];
    } catch (e) { return []; }
  });

  // --- EFFECTS ---
  useEffect(() => {
    localStorage.setItem('anatomy_mistakes_v5', JSON.stringify(mistakesVault));
  }, [mistakesVault]);

  useEffect(() => {
    if (selectedImage) {
        localStorage.setItem('ot_atlas_selected_image', selectedImage);
        document.body.style.overflow = 'hidden';
    } else {
        localStorage.removeItem('ot_atlas_selected_image');
        document.body.style.overflow = '';
    }
    return () => { document.body.style.overflow = ''; };
  }, [selectedImage]);

  useEffect(() => {
    localStorage.setItem('ot_atlas_image_expanded', String(isImageExpanded));
  }, [isImageExpanded]);

  useEffect(() => {
    localStorage.setItem('ot_atlas_search', search);
  }, [search]);

  useEffect(() => {
    localStorage.setItem('ot_atlas_filter_mistakes', String(showMistakesOnly));
  }, [showMistakesOnly]);

  useEffect(() => {
    localStorage.setItem('ot_atlas_filter_categories', JSON.stringify(selectedCategories));
  }, [selectedCategories]);

  useEffect(() => {
    if (!selectedImage || isQuizActive) {
        cancel();
    }
  }, [selectedImage, isQuizActive, cancel]);

  // --- HANDLERS ---
  const handleResolveMistake = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    setMistakesVault(prev => prev.filter(mId => mId !== id));
  };

  const handleWipeVault = () => {
    if (confirm("Permanently remove all diagrams from your mistakes list?")) {
        setMistakesVault([]);
        setShowMistakesOnly(false);
    }
  };

  const handleGridClick = (url: string) => {
    setSelectedImage(url);
    setIsQuizActive(true); // Enter quiz immediately
  };

  const categories = useMemo(() => {
    const cats = new Set(data.map(q => q.category));
    return Array.from(cats).sort((a: string, b: string) => 
      a.localeCompare(b, undefined, { numeric: true, sensitivity: 'base' })
    );
  }, [data]);

  const atlasItems = useMemo(() => {
    const imagesMap = new Map<string, Question[]>();

    data.forEach(q => {
      const url = q.questionImage || q.answerImage;
      if (url) {
        if (!imagesMap.has(url)) imagesMap.set(url, []);
        imagesMap.get(url)?.push(q);
      }
    });

    let items = Array.from(imagesMap.entries()).map(([url, questions]) => ({
      url,
      category: questions[0].category,
      related: questions,
      title: questions[0].questionText
        .replace(/^In the diagram,?\s*/i, '')
        .replace(/^Identify the\s+/i, '')
        .replace(/^Where is the\s+/i, '')
        .replace(/\??$/i, '')
        .trim(),
      hasMistake: questions.some(q => mistakesVault.includes(q.id))
    }));

    if (showMistakesOnly) items = items.filter(item => item.hasMistake);
    if (selectedCategories.length > 0) items = items.filter(item => selectedCategories.includes(item.category));

    if (search.trim()) {
        const term = search.toLowerCase();
        items = items.filter(item => 
            item.category.toLowerCase().includes(term) || 
            item.related.some(r => r.questionText.toLowerCase().includes(term)) ||
            item.related.some(r => r.answerText.toLowerCase().includes(term))
        );
    }

    return items;
  }, [data, search, showMistakesOnly, selectedCategories, mistakesVault]);

  useEffect(() => {
    setVisibleLimit(24);
  }, [search, showMistakesOnly, selectedCategories]);

  useEffect(() => {
    if (isMounted.current) {
        // Handle closing via selectedImage nulling
        if (!selectedImage) {
            setIsQuizActive(false);
            setIsImageExpanded(false);
        }
    } else {
        isMounted.current = true;
    }
  }, [selectedImage]);

  const activeEntry = useMemo(() => atlasItems.find(i => i.url === selectedImage), [atlasItems, selectedImage]);
  const visibleItems = atlasItems.slice(0, visibleLimit);

  const handleReadAloud = () => {
    if (!activeEntry) return;
    if (isSpeaking && speakingId === 'atlas-summary') {
        cancel();
    } else {
        const points = activeEntry.related.map((p, i) => {
            const label = p.questionText.replace(/^In the diagram,?\s*/i, '').replace(/^Identify the\s+/i, '').replace(/\??$/i, '');
            return `Point ${i + 1}: ${label}. ${p.answerText}`;
        }).join('. ');

        const fullText = `Structure Breakdown for ${activeEntry.title}. ${points}`;
        speak(fullText, 'atlas-summary');
    }
  };

  const filterOptions: FilterOption[] = [
    {
        label: 'Mistakes Gallery',
        subLabel: `${mistakesVault.length} Active Errors`,
        icon: AlertTriangle,
        isActive: showMistakesOnly,
        onClick: () => { setShowMistakesOnly(!showMistakesOnly); if(!showMistakesOnly) { setSelectedCategories([]); } },
        colorTheme: 'amber'
    }
  ];

  return (
    <div className="h-full flex flex-col bg-slate-50/50 relative">

      {/* Sticky Header Control Bar */}
      <div className="px-4 py-4 md:px-8 md:py-6 sticky top-0 z-40 bg-white/80 backdrop-blur-md border-b border-slate-200/60 shadow-sm">
        <div className="max-w-7xl mx-auto flex gap-3 md:gap-4 items-center">
            <div className="flex-1 relative group">
                <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none">
                    <Search className="text-slate-400 group-focus-within:text-rose-500 transition-colors" size={18} />
                </div>
                <input 
                    type="text" 
                    placeholder={showMistakesOnly ? "Search errors in diagrams..." : "Search anatomical structures..."} 
                    value={search}
                    onChange={(e) => setSearch(e.target.value)}
                    className="w-full pl-11 pr-4 py-3 rounded-xl bg-slate-100/50 border border-slate-200 text-slate-700 font-medium text-sm focus:bg-white focus:border-rose-300 focus:ring-4 focus:ring-rose-100 outline-none transition-all placeholder:text-slate-400"
                />
            </div>
            <button 
                onClick={() => setIsFilterOpen(true)}
                className={`h-[46px] px-4 md:px-6 rounded-xl border transition-all flex items-center gap-2 font-bold text-xs uppercase tracking-wider ${
                    selectedCategories.length > 0 || showMistakesOnly 
                    ? 'bg-rose-50 border-rose-200 text-rose-700' 
                    : 'bg-white border-slate-200 text-slate-600 hover:border-slate-300'
                }`}
            >
                <Filter size={16} />
                <span className="hidden md:inline">Filters</span>
                {(selectedCategories.length > 0 || showMistakesOnly) && (
                    <span className="flex h-5 w-5 items-center justify-center rounded-full bg-rose-600 text-[9px] text-white ml-1">
                        {[selectedCategories.length > 0, showMistakesOnly].filter(Boolean).length}
                    </span>
                )}
            </button>
        </div>

        {/* Diagnostic Mode Banner */}
        {showMistakesOnly && (
            <div className="max-w-7xl mx-auto mt-3 animate-in slide-in-from-top-2 fade-in">
                <div className="bg-amber-50 border border-amber-100 rounded-lg px-4 py-2 flex items-center justify-between text-amber-800 shadow-sm">
                    <div className="flex items-center gap-2">
                        <AlertTriangle size={16} className="text-amber-600" />
                        <span className="text-xs font-bold uppercase tracking-wide">Diagnostic Mode Active</span>
                    </div>
                    <span className="text-[10px] font-bold opacity-70">{atlasItems.length} Diagrams Found</span>
                </div>
            </div>
        )}
      </div>

      {/* Main Content Grid */}
      <div className="flex-1 overflow-y-auto px-4 md:px-8 py-6 custom-scrollbar scroll-smooth">
